BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?analysis ?analysisName ?dep ?target ?targetName ?targetType WHERE {
  ?analysis rdf:type vocab:simulation%20configuration .
  ?analysis vocab:NamedElement_name ?analysisName .
  FILTER(CONTAINS(LCASE(STR(?analysisName)), LCASE("duration%20analysis")))
  OPTIONAL {
    ?analysis ?dep ?target .
    FILTER(?dep IN (vocab:satisfy, vocab:verify, vocab:Dependency_supplier, vocab:Dependency_client))
    OPTIONAL { ?target vocab:NamedElement_name ?targetName }
    OPTIONAL { ?target rdf:type ?targetType }
  }
}
LIMIT 50

