  ?analysis vocab:NamedElement_name ?analysisName .
  FILTER(CONTAINS(LCASE(STR(?analysisName)), LCASE("duration%20analysis")))
  OPTIONAL {
    ?analysis vocab:Element_ownedElement ?ownedElem .
    OPTIONAL { ?ownedElem vocab:NamedElement_name ?ownedName }
    OPTIONAL { ?ownedElem rdf:type ?ownedType }
