BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?elemName ?dep ?target ?targetName ?targetType WHERE {
  ?elem rdf:type vocab:simulation%20configuration .
  ?elem vocab:NamedElement_name ?elemName .
  FILTER(CONTAINS(LCASE(STR(?elemName)), LCASE("duration%20analysis")))
  ?elem ?dep ?target .
  FILTER(?dep != rdf:type && ?dep != vocab:NamedElement_name && ?dep != vocab:Element_owner && ?dep != vocab:Element_ownedElement && ?dep != vocab:Namespace_member && ?dep != vocab:Namespace_ownedMember && ?dep != vocab:Package_packagedElement && ?dep != vocab:Package_ownedType && ?dep != vocab:MDObject_ID && ?dep != vocab:NamedElement_namespace && ?dep != vocab:NamedElement_qualifiedName && ?dep != vocab:PackageableElement_owningPackage && ?dep != vocab:PackageableElement_visibility__from_PackageableElement && ?dep != vocab:NamedElement__namespaceOfMember && ?dep != vocab:Element__commentOfAnnotatedElement && ?dep != vocab:Element__relationshipOfRelatedElement && ?dep != vocab:Element_appliedStereotypeInstance && ?dep != vocab:Element_ownedComment && ?dep != vocab:Namespace_ownedDiagram && ?dep != vocab:Element__elementValueOfElement)
  OPTIONAL { ?target vocab:NamedElement_name ?targetName }
  OPTIONAL { ?target rdf:type ?targetType }
}
LIMIT 50

