BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?tc ?tcName ?hasVerify ?supplierName WHERE {
  {
    SELECT DISTINCT ?tc ?tcName WHERE {
      ?tc rdf:type vocab:test%20case .
      ?tc vocab:NamedElement_name ?tcName .
      FILTER(CONTAINS(LCASE(STR(?tcName)), LCASE("duration")))
    }
  }
  OPTIONAL {
    ?verifyDep rdf:type vocab:verify .
    ?verifyDep vocab:Dependency_client ?tc .
    ?verifyDep vocab:Dependency_supplier ?supplier .
    ?supplier vocab:NamedElement_name ?supplierName .
    BIND("yes" AS ?hasVerify)
  }
}
ORDER BY ?tcName
LIMIT 50

